//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Table conditional formatting: cnfStyle bitmask, tblLook gating,
//!        tblStylePr override precedence".
//!
//! Each `#[test]` below encodes a behavioural constraint mined from
//! ECMA-376 / ISO 29500 / MS-OI29500 (see the per-test `refs` in the assert
//! messages). A FAILING assertion in this file is NOT a flaky test to be made
//! green: it encodes a real Word-compliance gap in the stemma engine. Fix the
//! engine (or, if the test encodes the wrong expectation, fix the test from the
//! spec) — never weaken the assertion to make it pass.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim. For paragraph `w:cnfStyle`, stemma's serializer
//! actively rebuilds `pPr/cnfStyle` from the typed model (build_paragraph_-
//! properties), so XML-ordering / normalization assertions on the re-serialized
//! `w:cnfStyle` are valid serializer-structure claims. The same is true for the
//! table `w:tblLook`: `serialize_table_node` unconditionally re-emits the six
//! named on/off attributes from the typed `TblLook`, so the synthesized named
//! attrs are stemma's OWN output and an xml assertion on them is valid.
//! `opensClean` exercises the package validator (`stemma::api::validate`).

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: minimal-.docx plumbing ────────────────────────────────────────

/// The WordprocessingML main namespace, shared by document.xml and styles.xml.
const W_NS: &str = "http://schemas.openxmlformats.org/wordprocessingml/2006/main";

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. Each `extra_parts` entry is
/// `(part_name, xml)` (e.g. `("word/styles.xml", "<?xml …><w:styles…>")`); an
/// `[Content_Types].xml` Override and a `word/_rels/document.xml.rels`
/// relationship are synthesized for known part kinds.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="{W_NS}"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-Types overrides + document rels for any extra parts.
    let mut overrides = String::new();
    let mut doc_rels_entries = String::new();
    for (rel_idx, (part_name, _)) in (1..).zip(extra_parts.iter()) {
        let part_path = format!("/{part_name}");
        let (content_type, rel_type, target) = match *part_name {
            "word/styles.xml" => (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            ),
            "word/numbering.xml" => (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            ),
            other => panic!("make_docx: unknown extra part {other} — add its content-type"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_path}" ContentType="{content_type}"/>"#
        ));
        doc_rels_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{rel_idx}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_entries}</Relationships>"#
    );

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return the textual content of `word/document.xml`.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse `bytes`, re-serialize to a `.docx` via the default export options, and
/// return the resulting `word/document.xml`. For paragraph cnfStyle and table
/// tblLook this reflects stemma's ACTIVE serializer output (both are rebuilt
/// from the typed model), so xml-ordering / normalization assertions are valid.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// Assert the substrings `needles` appear, in the given order, inside `xml`.
/// This is the daily-test translation of an `xmlRegex` ordering pattern such as
/// `a="1"[^>]*b="1"[^>]*c="1"`: each needle must be found, and at a strictly
/// increasing byte offset. Returns Ok(()) or an Err describing the first
/// out-of-order / missing needle.
fn assert_in_order(xml: &str, needles: &[&str]) -> Result<(), String> {
    let mut cursor = 0usize;
    let mut prev = "<start>";
    for needle in needles {
        match xml[cursor..].find(needle) {
            Some(rel) => {
                cursor += rel + needle.len();
                prev = needle;
            }
            None => {
                // Distinguish "missing entirely" from "out of order".
                if xml.contains(needle) {
                    return Err(format!(
                        "{needle:?} present but does not appear after {prev:?} (out of order)"
                    ));
                }
                return Err(format!("{needle:?} not found after {prev:?}"));
            }
        }
    }
    Ok(())
}

/// `opensClean`: `stemma::api::validate` reports no issues.
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{ctx} — expected the package to open clean (no validation issues), got ok={} issues={:?}",
        report.ok,
        report.issues
    );
}

