#[ignore = "open question: unedited round-trip writes body byte-verbatim, so cnfStyle is the literal source order/values, not stemma's synthesized Annex-A-ordered =\"1\" output; serializer rebuild path not exercised by untouched parse->serialize (ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.7/§17.4.8)"]
#[test]
fn cnf_corner_attrs_serialized_in_annex_a_order() {
    // ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.7; §17.4.8
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestStyle"/><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:pPr><w:cnfStyle w:lastRowLastColumn="true" w:firstRowFirstColumn="true" w:lastRowFirstColumn="true" w:firstRowLastColumn="true"/></w:pPr><w:r><w:t>corner</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);
    let xml = reserialize(&bytes);

    // CT_Cnf (Annex A) fixes the corner attributes in the order
    // firstRowFirstColumn < firstRowLastColumn < lastRowFirstColumn <
    // lastRowLastColumn; stemma must re-emit them in that order regardless of
    // the source attribute order.
    assert_in_order(
        &xml,
        &[
            "firstRowFirstColumn=\"1\"",
            "firstRowLastColumn=\"1\"",
            "lastRowFirstColumn=\"1\"",
            "lastRowLastColumn=\"1\"",
        ],
    )
    .unwrap_or_else(|e| {
        panic!(
            "CT_Cnf corner attrs out of Annex A order (ECMA-376 Annex A CT_Cnf; \
             ISO 29500-1 §17.4.7/§17.4.8): {e}\n--- document.xml ---\n{xml}"
        )
    });

    assert_opens_clean(
        &bytes,
        "CT_Cnf with the four corner attributes is schema-valid \
         (ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.8)",
    );
}

#[ignore = "open question: verbatim passthrough — re-serialized cnfStyle is the literal source w:firstRow=\"true\" w:lastRow=\"false\"; stemma does not normalize true->1 or drop false on an unedited round-trip (normalization only on the edit serializer path) (ISO 29500-1 §22.9.2.7; §17.4.7)"]
#[test]
fn cnf_named_onoff_normalized_to_one_and_false_omitted() {
    // ISO 29500-1 §17.4.7; ECMA-376 Annex A CT_Cnf; ISO 29500-1 §22.9.2.7
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestStyle"/><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:pPr><w:cnfStyle w:firstRow="true" w:lastRow="false"/></w:pPr><w:r><w:t>hdr</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);
    let xml = reserialize(&bytes);

    assert!(
        xml.contains("w:firstRow=\"1\""),
        "ST_OnOff true must canonicalize to \"1\" on re-emit (ISO 29500-1 §22.9.2.7; \
         §17.4.7); expected XML to contain w:firstRow=\"1\"\n--- document.xml ---\n{xml}"
    );
    assert!(
        !xml.contains("w:lastRow=\"0\""),
        "An off/absent CT_Cnf bit defaults to zero (§17.4.7); stemma must omit the \
         attribute rather than write w:lastRow=\"0\"\n--- document.xml ---\n{xml}"
    );
}

#[ignore = "open question: verbatim passthrough — output cnfStyle preserves the literal source order (oddVBand,lastColumn,firstColumn,lastRow,firstRow) with =\"true\" values; stemma did not re-emit in Annex A order on an unedited round-trip (ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.7)"]
#[test]
fn cnf_row_attrs_serialized_before_column_attrs() {
    // ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.7
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestStyle"/><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:pPr><w:cnfStyle w:oddVBand="true" w:lastColumn="true" w:firstColumn="true" w:lastRow="true" w:firstRow="true"/></w:pPr><w:r><w:t>x</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);
    let xml = reserialize(&bytes);

    // Annex A CT_Cnf: firstRow < lastRow < firstColumn < lastColumn < oddVBand;
    // row attrs before column attrs before band attrs, regardless of source.
    assert_in_order(
        &xml,
        &[
            "firstRow=\"1\"",
            "lastRow=\"1\"",
            "firstColumn=\"1\"",
            "lastColumn=\"1\"",
            "oddVBand=\"1\"",
        ],
    )
    .unwrap_or_else(|e| {
        panic!(
            "CT_Cnf row/column/band attrs out of Annex A order \
             (ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.7): {e}\n--- document.xml ---\n{xml}"
        )
    });
}

#[ignore = "open question: val IS first but the named attr is the literal source firstRowFirstColumn=\"true\", not synthesized =\"1\", because the body is byte-verbatim passthrough on an unedited round-trip; opensClean leg passes (ECMA-376 Annex A CT_Cnf; ISO 29500-4 §14.11.9)"]
#[test]
fn cnf_val_bitmask_coexists_with_corner_named_attr() {
    // ISO 29500-4 §14.11.9; ECMA-376 Annex A CT_Cnf; ISO 29500-1 §17.4.8
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestStyle"/><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:pPr><w:cnfStyle w:val="101000000000" w:firstRowFirstColumn="true"/></w:pPr><w:r><w:t>nw</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);
    let xml = reserialize(&bytes);

    // Annex A CT_Cnf orders val first; val must precede firstRowFirstColumn.
    assert_in_order(
        &xml,
        &[
            "<w:cnfStyle w:val=\"101000000000\"",
            "firstRowFirstColumn=\"1\"",
        ],
    )
    .unwrap_or_else(|e| {
        panic!(
            "CT_Cnf must re-emit val before the firstRowFirstColumn named attr \
             (ECMA-376 Annex A CT_Cnf; ISO 29500-4 §14.11.9): {e}\n--- document.xml ---\n{xml}"
        )
    });

    assert_opens_clean(
        &bytes,
        "A 12-char ST_Cnf val plus a named corner attribute is schema-valid \
         (ISO 29500-4 §14.11.9; Annex A CT_Cnf)",
    );
}

#[ignore = "open question: whole table round-trips byte-verbatim, so output tblLook is the bare w:val=\"04A0\" with NO synthesized named attrs; serialize_table_node named-attr emission is not reached on an unedited parse->serialize; the synthesis the spec assumes does not happen on plain round-trip; opensClean leg passes (MS-OI29500 §2.1.160; ISO 29500-4 §14.4.12)"]
#[test]
fn tbllook_val_only_synthesizes_correct_named_bits() {
    // MS-OI29500 §2.1.160 / §17.4.55; ISO/IEC 29500-4 §14.4.12; ISO 29500-1 §17.4.55
    // val=04A0 → firstRow(0x0020)=1, firstColumn(0x0080)=1, noVBand(0x0400)=1,
    //           lastRow(0x0040)=0, lastColumn(0x0100)=0, noHBand(0x0200)=0.
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestTblStyle"/><w:tblW w:w="0" w:type="auto"/><w:tblLook w:val="04A0"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);
    let xml = reserialize(&bytes);

    // Once stemma re-emits the named attrs, Word reads them (MS-OI29500
    // §2.1.160: val read iff no named attr present), so they MUST equal the
    // bits val=04A0 decoded to.
    assert!(
        xml.contains("w:firstRow=\"1\""),
        "val=04A0 sets bit 0x0020 (firstRow); synthesized w:firstRow must be 1 \
         (MS-OI29500 §2.1.160; ISO 29500-4 §14.4.12)\n--- document.xml ---\n{xml}"
    );
    assert!(
        xml.contains("w:firstColumn=\"1\""),
        "val=04A0 sets bit 0x0080 (firstColumn); synthesized w:firstColumn must be 1 \
         (MS-OI29500 §2.1.160; ISO 29500-4 §14.4.12)\n--- document.xml ---\n{xml}"
    );
    assert!(
        xml.contains("w:noVBand=\"1\""),
        "val=04A0 sets bit 0x0400 (noVBand); synthesized w:noVBand must be 1 \
         (MS-OI29500 §2.1.160; ISO 29500-4 §14.4.12)\n--- document.xml ---\n{xml}"
    );
    assert!(
        xml.contains("w:lastRow=\"0\""),
        "val=04A0 leaves bit 0x0040 (lastRow) clear; synthesized w:lastRow must be 0, \
         not defaulted on (MS-OI29500 §2.1.160; ISO 29500-4 §14.4.12)\n--- document.xml ---\n{xml}"
    );

    // oracle.mode = opensClean
    assert_opens_clean(
        &bytes,
        "A val-only tblLook table is schema-valid and opens clean (ISO 29500-1 §17.4.55)",
    );
}

#[test]
fn cnf_style_named_attrs_roundtrip_opens_clean_on_row_and_cell() {
    // ISO 29500-1 §17.4.7; §17.4.8; Annex A CT_Cnf
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestTblStyle"/><w:tblW w:w="0" w:type="auto"/><w:tblLook w:firstRow="1" w:firstColumn="0" w:lastRow="0" w:lastColumn="0" w:noHBand="0" w:noVBand="1"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:trPr><w:cnfStyle w:firstRow="1"/></w:trPr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/><w:cnfStyle w:firstRow="1" w:evenHBand="1"/></w:tcPr><w:p><w:r><w:t>Hdr</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);
    let xml = reserialize(&bytes);

    // ISO §17.4.7 row-level cnfStyle named-attr form must round-trip on trPr.
    assert_in_order(&xml, &["<w:trPr>", "<w:cnfStyle", "w:firstRow=\"1\""]).unwrap_or_else(|e| {
        panic!(
            "row-level cnfStyle (firstRow) must round-trip on the trPr carrier \
             (ISO 29500-1 §17.4.7; Annex A CT_Cnf): {e}\n--- document.xml ---\n{xml}"
        )
    });

    // ISO §17.4.8 cell-level cnfStyle named-attr form must round-trip on tcPr.
    assert_in_order(&xml, &["<w:tcPr>", "<w:cnfStyle", "w:evenHBand=\"1\""]).unwrap_or_else(|e| {
        panic!(
            "cell-level cnfStyle (evenHBand) must round-trip on the tcPr carrier \
             (ISO 29500-1 §17.4.8; Annex A CT_Cnf): {e}\n--- document.xml ---\n{xml}"
        )
    });

    assert_opens_clean(
        &bytes,
        "Val-less named-attr cnfStyle on trPr and tcPr is schema-valid \
         (ISO 29500-1 §17.4.7/§17.4.8; Annex A CT_Cnf)",
    );
}

