#[test]
fn novband_suppresses_column_banding_with_colbandsize_set() {
    // ISO 29500-1 §17.4.55; MS-OI29500 §2.1.160; ISO 29500-4 §14.4.12; MS-OI29500 §17.7.6.5
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="VB"/><w:tblW w:w="0" w:type="auto"/><w:tblLook w:firstRow="0" w:lastRow="0" w:firstColumn="0" w:lastColumn="0" w:noHBand="1" w:noVBand="1"/></w:tblPr><w:tblGrid><w:gridCol w:w="1500"/><w:gridCol w:w="1500"/><w:gridCol w:w="1500"/></w:tblGrid><w:tr><w:tc><w:tcPr/><w:p><w:r><w:t>c0</w:t></w:r></w:p></w:tc><w:tc><w:tcPr/><w:p><w:r><w:t>c1</w:t></w:r></w:p></w:tc><w:tc><w:tcPr/><w:p><w:r><w:t>c2</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="table" w:styleId="VB"><w:name w:val="VB"/><w:tblPr><w:tblStyleColBandSize w:val="1"/></w:tblPr><w:tblStylePr w:type="band1Vert"><w:tcPr><w:shd w:val="clear" w:color="auto" w:fill="AAAAAA"/></w:tcPr></w:tblStylePr><w:tblStylePr w:type="band2Vert"><w:tcPr><w:shd w:val="clear" w:color="auto" w:fill="BBBBBB"/></w:tcPr></w:tblStylePr></w:style></w:styles>"#;
    let bytes = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &bytes,
        "A noVBand-gated styled table with band1Vert/band2Vert and colBandSize is valid OOXML \
         and opens clean (ISO 29500-1 §17.4.55; MS-OI29500 §2.1.160)",
    );
}

#[test]
fn tbllook_omitted_defaults_to_named_attrs_not_consulted() {
    // MS-OI29500 §2.1.160 / §17.4.55; ISO 29500-1 §17.4.55; ISO 29500-4 §14.4.12
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TestStyle"/><w:tblW w:w="0" w:type="auto"/><w:tblLook w:firstRow="true" w:val="0000"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let bytes = make_docx(body, &[]);

    // oracle.mode = opensClean (val=0000 ignored; firstRow consulted)
    assert_opens_clean(
        &bytes,
        "CT_TblLook permits a named attribute and val simultaneously; the package is \
         schema-valid and opens clean, consulting only the named firstRow attribute \
         (MS-OI29500 §2.1.160; ISO 29500-1 §17.4.55)",
    );
}
